export async function chat(messages: { role: 'user' | 'model', parts: { text: string }[] }[], context?: string) {
    if (!GEMINI_API_KEY) {
        console.error("CRITICAL: GEMINI_API_KEY is missing from environment variables.");
        throw new Error("I'm waiting for my scientific core to be initialized (API Key missing). Please contact support.");
    }

    try {
        const genAI = new GoogleGenerativeAI(GEMINI_API_KEY);

        let dynamicPrompt = SYSTEM_PROMPT;
        if (context) {
            dynamicPrompt += `\n[CURRENT USER CONTEXT]: The user is currently viewing the page: "${context}". Tailor your response to this location.`;
        }

        const model = genAI.getGenerativeModel({
            model: "gemini-2.5-flash",
            systemInstruction: dynamicPrompt
        });

        const lastMessage = messages[messages.length - 1].parts[0].text;
        const history = messages.slice(0, -1);

        const chatSession = model.startChat({ history });
        const result = await chatSession.sendMessage(lastMessage);
        const response = await result.response;
        return response.text();
    } catch (error: any) {
        console.error("AI Agent Core Error:", error);
        throw new Error(error.message || "I had a small glitch in my simulation logic. Could you try asking that again?");
    }
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { RateLimiter, LIMITS } from './limiter';

describe('RateLimiter', () => {
    let limiter: RateLimiter;

    beforeEach(() => {
        limiter = new RateLimiter();
        vi.useFakeTimers();
    });

    afterEach(() => {
        vi.useRealTimers();
    });

    it('should allow requests properly within limits', () => {
        const res = limiter.check('chat', '127.0.0.1');
        expect(res.allowed).toBe(true);
    });

    it('should enforce user limits for chat', () => {
        const ip = '1.2.3.4';
        const limit = LIMITS.chat.userLimit;

        // Fill up to limit
        for (let i = 0; i < limit; i++) {
            expect(limiter.check('chat', ip).allowed).toBe(true);
        }

        // Exceed limit
        const blocked = limiter.check('chat', ip);
        expect(blocked.allowed).toBe(false);
        expect(blocked.reason).toContain('too fast');
    });

    it('should enforce global limits for chat', () => {
        const limit = LIMITS.chat.globalLimit;

        // Fill up global limit with unique IPs
        for (let i = 0; i < limit; i++) {
            expect(limiter.check('chat', `10.0.0.${i}`).allowed).toBe(true);
        }

        // Exceed global limit
        const blocked = limiter.check('chat', '10.0.0.999');
        expect(blocked.allowed).toBe(false);
        expect(blocked.reason).toContain('System is busy');
    });

    it('should maintain independent buckets for chat and tts', () => {
        const ip = '5.5.5.5';

        // Exhaust Chat Limit
        for (let i = 0; i < LIMITS.chat.userLimit; i++) {
            limiter.check('chat', ip);
        }
        expect(limiter.check('chat', ip).allowed).toBe(false);

        // TTS should still be allowed
        expect(limiter.check('tts', ip).allowed).toBe(true);
    });

    it('should enforce stricter limits for TTS', () => {
        const ip = '6.6.6.6';
        const ttsLimit = LIMITS.tts.userLimit;

        for (let i = 0; i < ttsLimit; i++) {
            expect(limiter.check('tts', ip).allowed).toBe(true);
        }

        expect(limiter.check('tts', ip).allowed).toBe(false);
    });

    it('should reset limits after window expiration', () => {
        const ip = '7.7.7.7';

        // Block user
        for (let i = 0; i < LIMITS.chat.userLimit; i++) {
            limiter.check('chat', ip);
        }
        expect(limiter.check('chat', ip).allowed).toBe(false);

        // Fast forward time past window
        vi.advanceTimersByTime(LIMITS.chat.windowMs + 1000);

        // Should be allowed again
        expect(limiter.check('chat', ip).allowed).toBe(true);
    });
});

interface RequestLog {
    timestamp: number;
    ip: string;
}

interface LimitConfig {
    globalLimit: number; // Max requests per minute globally
    userLimit: number;   // Max requests per minute per IP
    windowMs: number;    // Time window in milliseconds
}

const DEFAULT_CONFIG: LimitConfig = {
    globalLimit: 15,
    userLimit: 5,
    windowMs: 60 * 1000
};

// Distinct configurations for different actions
export const LIMITS: Record<string, LimitConfig> = {
    chat: {
        globalLimit: 15, // Free Tier Gemini Flash limit
        userLimit: 5,    // Fair use per user
        windowMs: 60 * 1000
    },
    tts: {
        globalLimit: 10, // Stricter limit for audio generation to save bandwidth/quota
        userLimit: 3,    // Prevent spamming generate-speech
        windowMs: 60 * 1000
    }
};

export class RateLimiter {
    private logs: Record<string, RequestLog[]> = {
        chat: [],
        tts: []
    };

    /**
     * Checks if a request is allowed for a specific action bucket.
     * @param action 'chat' | 'tts'
     * @param ip User IP address
     */
    check(action: string, ip: string): { allowed: boolean; reason?: string } {
        const config = LIMITS[action] || DEFAULT_CONFIG;
        const now = Date.now();

        // Ensure bucket exists
        if (!this.logs[action]) {
            this.logs[action] = [];
        }

        // 1. Clean up old logs (sliding window)
        this.logs[action] = this.logs[action].filter(log => now - log.timestamp < config.windowMs);

        const logs = this.logs[action];

        // 2. Global Limit Check
        if (logs.length >= config.globalLimit) {
            console.warn(`[LIMITER] Global limit reached for ${action}. Current: ${logs.length}, Max: ${config.globalLimit}`);
            return { allowed: false, reason: "System is busy (Global Rate Limit). Please wait a moment." };
        }

        // 3. User Limit Check
        const userLogs = logs.filter(log => log.ip === ip);
        if (userLogs.length >= config.userLimit) {
            console.warn(`[LIMITER] User limit reached for ${action} by ${ip}. Current: ${userLogs.length}, Max: ${config.userLimit}`);
            return { allowed: false, reason: "You are sending requests too fast. Please slow down." };
        }

        // 4. Record Request
        this.logs[action].push({ timestamp: now, ip });
        return { allowed: true };
    }
}

// Export a singleton instance
export const rateLimiter = new RateLimiter();
